SELECT

FROM ai_lowcode_domain
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'

  AND (
    domain_code LIKE CONCAT('%', #{keyword}, '%')
    OR domain_name LIKE CONCAT('%', #{keyword}, '%')
    OR domain_desc LIKE CONCAT('%', #{keyword}, '%')
  )


  AND status = #{status}


  AND parent_id = #{parentId}

ORDER BY sort ASC, id ASC

SELECT

FROM ai_lowcode_domain
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'
  AND id = #{id}
LIMIT 1

SELECT

FROM ai_lowcode_domain
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'
  AND domain_code = #{domainCode}
LIMIT 1

SELECT COUNT(1)
FROM ai_lowcode_domain
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'
  AND domain_code = #{domainCode}

  AND id != #{excludeId}

SELECT COUNT(1)
FROM ai_lowcode_domain
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'
  AND parent_id = #{parentId}
  AND domain_name = #{domainName}

  AND id != #{excludeId}

SELECT COUNT(1)
FROM ai_lowcode_domain
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'
  AND parent_id = #{parentId}
